svg.script:
(function () {
  var svg = document.documentElement;
  svg._chartInit = function (svgEl, ctx) {
var svg        = document.getElementById('root');
  var dataLayerEl = document.getElementById('data-layer');
  var ns         = 'http://www.w3.org/2000/svg';
  var isDark     = false;

  var PALETTE_LIGHT = {
    1:[0,212,232], 2:[0,184,122], 3:[245,158,11], 4:[244,63,94],
    5:[139,92,246], 6:[59,130,246], 7:[13,148,136], 8:[100,116,139]
  };
  var PALETTE_DARK = {
    1:[34,211,238], 2:[16,185,129], 3:[251,183,36], 4:[251,97,129],
    5:[167,139,250], 6:[96,165,250], 7:[45,212,191], 8:[148,163,184]
  };

  function cssVar(name) {
    return window.getComputedStyle(svg).getPropertyValue(name).trim();
  }

  function hexToRgb(h) {
    var n = parseInt(h.replace('#',''),16);
    return [(n>>16)&255,(n>>8)&255,n&255];
  }

  function blendRgb(base, bgHex, t) {
    var bg = hexToRgb(bgHex);
    return 'rgb('+[0,1,2].map(function(i){
      return Math.round(base[i]+(bg[i]-base[i])*t);
    }).join(',')+')';
  }

  function getTint(ci, depth) {
    var palette = isDark ? PALETTE_DARK : PALETTE_LIGHT;
    var base = palette[ci] || [128,128,128];
    var d    = Math.min(depth,4);
    var t    = parseFloat(cssVar((isDark ? '--blend-dark-d' : '--blend-d') + d));
    var bg   = cssVar(isDark ? '--bg-dark' : '--bg-light');
    return blendRgb(base, bg, t);
  }

  var TOTAL = 819293, S = 400/TOTAL;
  var COL_W = 160, COL_GAP = 4;
  var COL_DUR   = 0.8;
  var COL_START = [0, 0.25, 0.50, 0.75, 1.00];
  /* per-column stagger: cap at 0.25s but scale down so each column
     spreads within ~1s regardless of cell count */
  var COL_ANIM_WINDOW = 1.0;
  function colX(d){ return 68+d*(COL_W+COL_GAP); }

  var nodes = [
    ['flare',819293,0,1],
    ['analytics',48716,1,1],['animate',93278,1,2],['data',30284,1,3],
    ['display',24254,1,4],['flex',4877,1,5],['physics',29934,1,6],
    ['query',75492,1,7],['scale',31294,1,8],['util',91480,1,2],['vis',389684,1,3],
    ['cluster',15207,2,1],['graph',26435,2,1],['optimization',7074,2,1],
    ['Easing',17010,2,2],['FunctionSequence',5842,2,2],['interpolate',23457,2,2],
    ['Parallel',5176,2,2],['Scheduler',5593,2,2],['Sequence',5534,2,2],
    ['Transition',9201,2,2],['Transitioner',19975,2,2],
    ['converters',18349,2,3],['DataField',1759,2,3],['DataSchema',2165,2,3],
    ['DataSource',3331,2,3],['DataUtil',3322,2,3],
    ['DirtySprite',8833,2,4],['LineSprite',1732,2,4],['RectSprite',3623,2,4],['TextSprite',10066,2,4],
    ['FlexSprite',4877,2,5],
    ['NBodyForce',10498,2,6],['Particle',2822,2,6],['Simulation',9983,2,6],
    ['Spring',2213,2,6],['SpringForce',1681,2,6],
    ['AggregateExpression',1616,2,7],['Arithmetic',3891,2,7],['Comparison',5103,2,7],
    ['DateUtil',4141,2,7],['Expression',5130,2,7],['Fn',3240,2,7],
    ['Query',13896,2,7],['StringUtil',4130,2,7],
    ['LogScale',3151,2,8],['OrdinalScale',3770,2,8],['QuantitativeScale',4839,2,8],
    ['Scale',4268,2,8],['TimeScale',5833,2,8],
    ['Arrays',8258,2,2],['Colors',10001,2,2],['Dates',8217,2,2],['Displays',12555,2,2],
    ['Geometry',10993,2,2],['math',9346,2,2],['Property',5559,2,2],
    ['Sort',6887,2,2],['Stats',6557,2,2],
    ['axis',33886,2,3],['controls',53040,2,3],['vis_data',110230,2,3],
    ['legend',36003,2,3],['operator',139985,2,3],
    ['Axis',24593,3,3],['CartesianAxes',6703,3,3],
    ['AnchorControl',2138,3,3],['ClickControl',3824,3,3],['ControlList',4665,3,3],
    ['DragControl',2649,3,3],['HoverControl',4896,3,3],
    ['NavigationControl',7862,3,3],['PanZoomControl',5771,3,3],
    ['SelectionControl',7852,3,3],['TooltipControl',8435,3,3],
    ['Data',20544,3,3],['DataList',19788,3,3],['DataSprite',10349,3,3],
    ['NodeSprite',19382,3,3],['render',8514,3,3],['ScaleBinding',11275,3,3],['Tree',7147,3,3],
    ['Legend',20859,3,3],['LegendItem',4614,3,3],['LegendRange',10530,3,3],
    ['distortion',14219,3,3],['encoder',10759,3,3],['filter_op',11893,3,3],
    ['label',17057,3,3],['layout',67804,3,3],
    ['AxisLayout',6702,4,3],['CircleLayout',5618,4,3],['CirclePackingLayout',12003,4,3],
    ['ForceDirectedLayout',8411,4,3],['IcicleTreeLayout',4864,4,3],
    ['RadialTreeLayout',7982,4,3],['StackedAreaLayout',9121,4,3],
    ['BifocalDistortion',4461,4,3],['Distortion',6314,4,3],['FisheyeDistortion',3444,4,3],
  ];

  var yPos = {
    'flare':100,
    'analytics':100,'animate':123.8,'data':169.5,'display':184.3,'flex':199.1,
    'physics':201.1,'query':214.8,'scale':251.5,'util':265.2,'vis':310.3,
    'cluster':100,'graph':107.4,'optimization':120.2,
    'Easing':123.8,'FunctionSequence':132.0,'interpolate':134.8,
    'Parallel':143.2,'Scheduler':145.7,'Sequence':147.9,'Transition':150.2,'Transitioner':153.9,
    'converters':169.5,'DataField':178.5,'DataSchema':179.3,'DataSource':180.3,'DataUtil':181.9,
    'DirtySprite':184.3,'LineSprite':188.6,'RectSprite':189.4,'TextSprite':190.8,
    'FlexSprite':199.1,
    'NBodyForce':201.1,'Particle':206.2,'Simulation':207.5,'Spring':212.3,'SpringForce':213.4,
    'AggregateExpression':214.8,'Arithmetic':215.6,'Comparison':217.5,'DateUtil':221.2,
    'Expression':223.5,'Fn':225.8,'Query':227.4,'StringUtil':234.0,
    'LogScale':251.5,'OrdinalScale':252.9,'QuantitativeScale':254.4,'Scale':256.1,'TimeScale':257.6,
    'Arrays':265.2,'Colors':268.6,'Dates':272.4,'Displays':275.8,'Geometry':281.6,
    'math':286.4,'Property':290.2,'Sort':292.5,'Stats':295.1,
    'axis':310.3,'controls':323.8,'vis_data':347.0,'legend':374.2,'operator':388.7,
    'Axis':310.3,'CartesianAxes':322.2,
    'AnchorControl':323.8,'ClickControl':324.8,'ControlList':326.5,'DragControl':329.0,
    'HoverControl':330.2,'NavigationControl':332.6,'PanZoomControl':336.1,
    'SelectionControl':338.7,'TooltipControl':342.2,
    'Data':347.0,'DataList':355.0,'DataSprite':362.4,'NodeSprite':366.5,
    'render':374.0,'ScaleBinding':377.4,'Tree':382.8,
    'Legend':374.2,'LegendItem':383.3,'LegendRange':384.9,
    'distortion':388.7,'encoder':394.5,'filter_op':399.0,'label':403.3,'layout':410.5,
    'AxisLayout':410.5,'CircleLayout':413.4,'CirclePackingLayout':416.0,
    'ForceDirectedLayout':420.8,'IcicleTreeLayout':424.5,
    'RadialTreeLayout':426.8,'StackedAreaLayout':430.2,
    'BifocalDistortion':388.7,'Distortion':390.6,'FisheyeDistortion':393.0,
  };

  var makeEl = ctx.el;

  /* pre-count cells per depth so colStagger() has totals before buildCells runs */
  var depthTotal=[0,0,0,0,0];
  nodes.forEach(function(n){ depthTotal[n[2]]++; });

  var depthCount=[0,0,0,0,0];
  var cellEls=[];

  function buildCells(){
    nodes.forEach(function(n){
      var name=n[0],val=n[1],depth=n[2],ci=n[3];
      var x=colX(depth),y=yPos[name]||100,h=Math.max(1.5,val*S);
      var idx=depthCount[depth]++;
      var stagger=Math.min(0.25, COL_ANIM_WINDOW / Math.max(depthTotal[depth], 1));
      var delay=(COL_START[depth]+idx*stagger).toFixed(2);

      var g=makeEl('g',{'class':'icell',
        'data-name':name,'data-val':val,'data-ci':ci,'data-depth':depth});

      // Ã‚Â§3 fix: inline opacity:0 before animation so CSS has no base value to snap back to.
      // animationend clears both animation and inline opacity, then adds .visible.
      g.style.opacity   = '0';
      g.style.animation = 'cellFade '+COL_DUR+'s ease-out '+delay+'s';
      g.addEventListener('animationend',function(){
        g.style.animation = 'none';
        g.style.opacity   = '';
        g.classList.add('visible');
      },{once:true});

      var r=makeEl('rect',{x:x,y:y,width:COL_W,height:h,
        fill:getTint(ci,depth),stroke:'white','stroke-width':'1',rx:depth<2?3:2});
      g.appendChild(r);

      if(h>=13){
        var t=makeEl('text',{x:x+6,y:y+h/2,'dominant-baseline':'central',
          'font-size':depth<=1?10:9,'font-weight':depth<=1?'500':'400',
          'fill':'white',
          'fill-opacity':depth>=3?'0.85':'1',
          'pointer-events':'none'});
        var ml=Math.floor(COL_W/5.8);
        t.textContent=name.length>ml?name.slice(0,ml-1)+'Ã¢â‚¬Â¦':name;
        g.appendChild(t);
      }
      dataLayerEl.appendChild(g);
      cellEls.push({r:r,ci:ci,depth:depth});
    });
    attachHover();
  }

  function recolor(){
    cellEls.forEach(function(c){
      c.r.setAttribute('fill',getTint(c.ci,c.depth));
    });
    buildLegend();
  }

  var MODULES=[
    {name:'analytics',val:'48,716',ci:1},{name:'animate',val:'93,278',ci:2},
    {name:'data',val:'30,284',ci:3},{name:'display',val:'24,254',ci:4},
    {name:'flex',val:'4,877',ci:5},{name:'physics',val:'29,934',ci:6},
    {name:'query',val:'75,492',ci:7},{name:'scale',val:'31,294',ci:8},
    {name:'util',val:'91,480',ci:2},
  ];

  function buildLegend(){
    var lg=document.getElementById('lgd-items');
    lg.innerHTML='';
    MODULES.forEach(function(m,i){
      var g=makeEl('g',{'class':'legend-row',transform:'translate(878,'+(146+i*42)+')'});
      var r=makeEl('rect',{x:0,y:0,width:14,height:14,rx:3,fill:getTint(m.ci,1)});
      var t=makeEl('text',{x:22,y:7,'class':'legend-label legend-row-label','dominant-baseline':'middle'}); t.textContent=m.name;
      var v=makeEl('text',{x:174,y:7,'class':'legend-value legend-row-value','text-anchor':'end','dominant-baseline':'middle'}); v.textContent=m.val;
      g.appendChild(r);g.appendChild(t);g.appendChild(v);lg.appendChild(g);
    });
  }

  var tip=document.getElementById('tip'),
      tipBg=document.getElementById('tip-bg'),tipBdr=document.getElementById('tip-bdr'),
      tipArr=document.getElementById('tip-arr'),tipName=document.getElementById('tip-name'),
      tipVal=document.getElementById('tip-val'),tipPct=document.getElementById('tip-pct');
  var BH=120,TAIL=12;

  function posTip(mx,my,name,val){
    /* set text first so getBBox measures real rendered width */
    tipName.textContent=name;
    tipVal.textContent=parseInt(val).toLocaleString()+' lines';
    tipPct.textContent=(parseInt(val)/TOTAL*100).toFixed(1)+'% of total';

    /* measure actual widths, derive hw */
    var pad=20;
    var hw=Math.max(
      tipName.getBBox().width+pad,
      tipVal.getBBox().width+pad,
      tipPct.getBBox().width+pad,
      60
    )/2;

    var rx9=12, tw=10;
    var tx=Math.max(hw+8,Math.min(mx,1092-hw));
    var flip=my<BH+TAIL+20;
    var bT,bB;
    if(!flip){ bT=my-TAIL-BH; bB=my-TAIL; }
    else     { bT=my+TAIL;    bB=my+TAIL+BH; }
    // clamp vertically
    if(bT<8)   { bT=8;   bB=bT+BH; }
    if(bB>610) { bB=610; bT=bB-BH; }
    var bL=tx-hw, bR=tx+hw;

    // background rect
    tipBg.setAttribute('x',bL); tipBg.setAttribute('y',bT);
    tipBg.setAttribute('width',hw*2); tipBg.setAttribute('height',BH);

    // open-path border Ã¢â‚¬â€ gap of Ã‚Â±tw at the tail side, no Z
    var openPath, tailPath;
    if(!flip){
      // tail below: gap at bottom centre
      openPath='M'+(tx+tw)+','+bB+
        ' L'+(bR-rx9)+','+bB+' Q'+bR+','+bB+' '+bR+','+(bB-rx9)+
        ' L'+bR+','+(bT+rx9)+' Q'+bR+','+bT+' '+(bR-rx9)+','+bT+
        ' L'+(bL+rx9)+','+bT+' Q'+bL+','+bT+' '+bL+','+(bT+rx9)+
        ' L'+bL+','+(bB-rx9)+' Q'+bL+','+bB+' '+(bL+rx9)+','+bB+
        ' L'+(tx-tw)+','+bB;
      tailPath='M'+(tx-tw)+','+bB+' L'+tx+','+(my)+' L'+(tx+tw)+','+bB;
    } else {
      // tail above: gap at top centre
      openPath='M'+(tx-tw)+','+bT+
        ' L'+(bL+rx9)+','+bT+' Q'+bL+','+bT+' '+bL+','+(bT+rx9)+
        ' L'+bL+','+(bB-rx9)+' Q'+bL+','+bB+' '+(bL+rx9)+','+bB+
        ' L'+(bR-rx9)+','+bB+' Q'+bR+','+bB+' '+bR+','+(bB-rx9)+
        ' L'+bR+','+(bT+rx9)+' Q'+bR+','+bT+' '+(bR-rx9)+','+bT+
        ' L'+(tx+tw)+','+bT;
      tailPath='M'+(tx+tw)+','+bT+' L'+tx+','+my+' L'+(tx-tw)+','+bT;
    }
    tipBdr.setAttribute('d',openPath);
    tipArr.setAttribute('d',tailPath);

    tipName.setAttribute('x',tx);tipName.setAttribute('y',bT+BH*0.22);
    tipVal.setAttribute('x',tx); tipVal.setAttribute('y',bT+BH*0.52);
    tipPct.setAttribute('x',tx); tipPct.setAttribute('y',bT+BH*0.80);
  }

  function attachHover(){
    dataLayerEl.querySelectorAll('.icell').forEach(function(c){
      c.addEventListener('mouseenter',function(e){
        dataLayerEl.classList.add('hovering');
        dataLayerEl.querySelectorAll('.icell').forEach(function(x){ x.classList.remove('hovered'); });
        c.classList.add('hovered');
        var sp=ctx.eventToSvgPoint(svg,e);
        posTip(sp.x,sp.y,c.dataset.name,c.dataset.val);
        tip.style.opacity='1';
      });
      c.addEventListener('mousemove',function(e){
        var sp=ctx.eventToSvgPoint(svg,e);
        posTip(sp.x,sp.y,c.dataset.name,c.dataset.val);
      });
      c.addEventListener('mouseleave',function(){
        c.classList.remove('hovered');
        tip.style.opacity='';
      });
    });
    /* hovering managed on container Ã¢â‚¬â€ prevents flicker when moving between adjacent cells */
    dataLayerEl.addEventListener('mouseleave',function(){
      dataLayerEl.classList.remove('hovering');
    });
  }



  buildCells();
  // gate hover dimming after last cell's animationend fires
  var d4stagger=Math.min(0.25, COL_ANIM_WINDOW / Math.max(depthTotal[4], 1));
  var lastDelay=COL_START[4]+(depthTotal[4]-1)*d4stagger;
  setTimeout(function(){dataLayerEl.classList.add('ready');},(lastDelay+COL_DUR+0.1)*1000);
  buildLegend();

  svgEl._onModeChange = function (wantDark) {
    isDark = !!wantDark;
    recolor();
  };
  recolor();
  };
  if (window.bootstrapChart) { window.bootstrapChart(svg); }
}());
